############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $newUnits = [ {name=>'diagnoses'}, {name=>'year',conversion=>{factor=>365*24*60*60,s=>1}}, {name=>'years',conversion=>{factor=>365*24*60*60,s=>1}}, {name=>'yr',conversion=>{factor=>365*24*60*60,s=>1}}, {name=>'yrs',conversion=>{factor=>365*24*60*60,s=>1}}, {name=>'y',conversion=>{factor=>365*24*60*60,s=>1}}, ]; $m=Real(248.719); Context()->flags->set(tolType=>'absolute',tolerance=>20); $rate = NumberWithUnits("$m diagnoses/yr",{newUnit=>$newUnits});
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis}[ xlabel={year}, ylabel={count}, ytick=, xmin=2005, xmax=2025, ymin=15000, ymax=26000, axis line style={->}, xtick={2005,2010,...,2025}, xticklabels={2005,2010,...,2025}, xticklabel style={rotate=-45}, axis y discontinuity=crunch, width=\orccaprintwidth, height=0.33\orccaprintwidth, ] \addplot[only marks] coordinates { (2007,19417) (2008,20426) (2009,19979) (2010,19861) (2011,20851) (2012,20426) (2013,21346) (2014,21683) (2015,22158) (2016,22135) (2017,23052) (2018,22769) (2019,24389) (2020,21766) (2021,22750) (2022,22691) }; \addplot+[domain=2005:2025] {248.719*(x - 2014.5) + 21606.1875}; \end{axis} \end{tikzpicture}
